export class OutfitImagePhpGeneratorCode {
    public version = '0.1.8';
    private files = {
        "libs\/gifCreator.php": "",
        "libs\/outfitter.php": "",
        "abuse_warning.png": "",
        "animoutfit.php": "",
        "cacheGenerator.php": "",
        "config.php": "",
        "index.php": "",
        "outfit.php": ""
    };

    addFilesToZip(zip) {
        for(const fileName in this.files) {
            const fileContent = this.files[fileName];
            const buffer = Buffer.from(fileContent, 'base64');
            zip.file(fileName, buffer);
        }
    }
}
